<?php
namespace Database\Seeders;
use Illuminate\Database\Seeder; use App\Models\User; use App\Models\Student; use App\Models\Goal; use App\Models\Reward; use App\Models\TeacherFeedback; use App\Models\Alert;
class DatabaseSeeder extends Seeder { public function run(): void { $parent=User::create(['name'=>'Parent User','email'=>'parent@example.com','password'=>'password','role'=>'parent']); $studentUser=User::create(['name'=>'Alex Johnson','email'=>'alex@example.com','password'=>'password','role'=>'student','parent_id'=>$parent->id,'grade'=>'9th Grade','school'=>'Lincoln High School']); $s=Student::create(['user_id'=>$studentUser->id,'parent_id'=>$parent->id,'age'=>14,'grade'=>'9th Grade','school'=>'Lincoln High School','strengths'=>'Mathematics, Science, Basketball','watch_areas'=>'Focus during independent work','parent_notes'=>'Alex responds well to positive reinforcement and gaming rewards.']); foreach([['No tardies this week','Attendance',100],['Complete all homework assignments','Academics',65],['Show respectful behavior in class','Behavior',100],['Study 30 minutes daily','Academics',0]] as $g) Goal::create(['student_id'=>$s->id,'created_by'=>$parent->id,'title'=>$g[0],'category'=>$g[1],'progress'=>$g[2],'target'=>'This week','success_criteria'=>'Complete']); Reward::create(['student_id'=>$s->id,'name'=>'Dinner out at favorite restaurant','condition'=>'Complete 100% of goals this month','category'=>'Food','progress'=>85]); TeacherFeedback::create(['student_id'=>$s->id,'teacher_name'=>'Ms. Rodriguez','subject'=>'Mathematics','engagement'=>'Inconsistent','work_completion'=>'Mostly Completed','comment'=>'Alex needs better focus during independent work time. He is capable but easily distracted.']); Alert::create(['student_id'=>$s->id,'title'=>'Missing Assignments Increasing','description'=>'3-week trend detected • Academics impacted','priority'=>'high']); Alert::create(['student_id'=>$s->id,'title'=>'Effort Score Dropping','description'=>'Dropped for 2 consecutive weeks','priority'=>'medium']); Alert::create(['student_id'=>$s->id,'title'=>'Behavior Improved','description'=>'Previous alert resolved • Great improvement!','priority'=>'low','status'=>'resolved']); } }
